      where: [
        {sym: "F", desc: "עומס מופעל"},
        {sym: "L", desc: "מרחק בין נקודות התמיכה"},
        {sym: "I", desc: "מומנט האינרציה של החתך"}
      ],
      note: "משמש לתכנון קשיחות כפיפה של גל צינורי מרוכב (ראו דוגמת עיצוב)."
