  flashcards: [
    {front: "מהו עקרון הפעולה המשולבת?", back: "שילוב שקול-דעת של חומרים שונים מניב צירוף תכונות טוב יותר מכל חומר מונוליתי בנפרד."},
    {front: "מהן שתי הפאזות בכל מרוכב?", back: "פאזת מטריצה (רציפה, עוטפת) ופאזה מפוזרת (מוטמעת, לרוב נושאת עומס)."},
    {front: "מהן ארבע הקבוצות העיקריות של חומרים מרוכבים?", back: "מרוכבי חלקיקים, מרוכבי סיבים, מרוכבים מבניים, וננו-מרוכבים."},
    {front: "מהו ההבדל העיקרי בין מרוכב חלקיקים גדול למרוכב מחוזק-פיזור?", back: "גודל החלקיק (מיקרומטרים לעומת ננומטרים) ורמת האינטראקציה עם המטריצה (מכניקת רצף לעומת רמה אטומית)."},
    {front: "מהו סרמט נפוץ ולמה הוא משמש?", back: "קרביד ממוסמר (WC או TiC במטריצת קובלט/ניקל) — משמש ככלי חיתוך לפלדות מוקשות."},
    {front: "מהי נוסחת אורך הסיב הקריטי?", back: "l_c = σ*_f·d / (2τ_c) — תלוי בחוזק הסיב, קוטרו וחוזק הקשר סיב-מטריצה."},
    {front: "מהו התנאי שסיב ייחשב 'רציף'?", back: "כאשר l > 15·l_c."},
    {front: "מהי הנחת isostrain ולאיזה מודול היא מובילה?", back: "עיוות שווה בכל הפאזות; מובילה למודול האורכי E_cl = E_mV_m + E_fV_f (גבול עליון)."},
    {front: "מהי הנחת isostress ולאיזה מודול היא מובילה?", back: "מאמץ שווה בכל הפאזות; מובילה למודול הרוחבי E_ct (גבול תחתון), נמוך בהרבה מהאורכי."},
    {front: "מהם שלושת תפקידי המטריצה במרוכב סיבים?", back: "העברת עומס בין הסיבים, הגנה על הסיבים מנזק שטחי, ומניעת התפשטות סדקים מסיב לסיב."},
    {front: "מהו ההבדל בין שערית, סיב וחוט?", back: "שערית — גביש בודד כמעט חף מפגם, חוזק חריג; סיב — פולי-גבישי/אמורפי, פולימרי או קרמי; חוט — מתכתי, קוטר גדול יחסית."},
    {front: "מהי יעילות חיזוק לסיבים אקראיים בתלת-ממד?", back: "כ-1/5 בלבד, לעומת 1 בכיוון הסיבים במרוכב מיושר."},
    {front: "מהו חיזוק טרנספורמציה במרוכבי מטריצה קרמית?", back: "חלקיקי ZrO2 עוברים מעבר פאזה טטרגונלי-מונוקליני בקדמת סדק, יוצרים מאמצי לחיצה שסוגרים אותו."},
    {front: "מהו ההבדל בין PMC, MMC ו-CMC?", back: "PMC — מטריצה פולימרית (נפוץ ביותר); MMC — מטריצה מתכתית (טמפ' גבוהה יותר); CMC — מטריצה קרמית (שיפור קשיחות שבירה)."},
    {front: "מהי משיכה (pultrusion) ולמה היא משמשת?", back: "משיכת סיבים מוספגי שרף דרך תבנית מחוממת — לייצור רציף של פרופילים בחתך קבוע (מוטות, צינורות)."},
    {front: "מהו פאנל סנדוויץ'?", back: "שני פנים חזקים (נושאי כפיפה) עם ליבה קלה (קצף, בלזה או כוורת) שנושאת גזירה ומפרידה בין הפנים."},
    {front: "כמה אחוז ממשקל בואינג 787 עשוי מרוכבים, לעומת בואינג 777?", back: "כ-50% ב-787 לעומת 11% ב-777."}
  ],

